
declare namespace GLOBAL {
    export var jibo:any;
}

declare module "module" {
    export function _resolveFilename(moduleId:string, opt:any):string;
    export function _nodeModulePaths(fromDir:string):string;
}

declare module "ipc" {
    import {EventEmitter} from 'events';
    class IPC extends EventEmitter {
        new();
        send(channel:string, ...args);
    }
    export = new IPC;
}

declare module "find-root" {
    function findRoot(dir?:string):string;
    export = findRoot;
}

declare module "uuid" {
    export function v4(): string;
}

declare module "pascal-case" {
    function convert(str:string): string;
    export = convert;
}

declare module "jibo-background" {
    export var NotificationsService;
}

declare module "animation-utilities" {
    export var body:any;
    export var LEDOutput:any;
    export var animate:any;
    export var visualize:any;
    export var MouseCoordinateWrangler:any;
    export var MouseTargetPositioner:any;
    export var JiboConfig:any;
    export var RobotInfo:any;

    class Time {
        _timestamp:[number, number];
        add(seconds:Time):Time;
        subtract(seconds:Time):number;
    }
    export class Clock {
        static currentTime():Time;
    }
    export class TrajectoryControllerSim {
        constructor(initialPosition:number, initialVelocity:number, initialTime:Time);
    }
    export class PosVelControllerSim {
        constructor(initialPosition:number, initialVelocity:number, initialTime:Time);
    }
    export namespace THREE {
        export class Vector3 {
            constructor(x:number, y:number, z:number);
            set (x:number, y:number, z:number):void;
        }
        export var Mesh:any;
        export var MeshBasicMaterial:any;
        export var SphereGeometry:any;
        export var Color:any;
    }
}

declare module "utils" {
    export var AnimationUtils, PathUtils, Timer, DelayedCall, perf;
}

declare module "resolve" {
    export function sync(name:string, options?:any):string;
}

declare module "jibo-keyframes" {
    export class conversion {
        static toPixelsX(meters:number):number;
        static toPixelsY(meters:number):number;
    }
}

declare module "hammerjs" {
    export var Manager:any;
    export var Pan:any;
    export var Swipe:any;
    export var DIRECTION_ALL:any;
    export var DIRECTION_RIGHT:any;
    export var DIRECTION_LEFT:any;
    export var DIRECTION_DOWN:any;
    export var DIRECTION_HORIZONTAL:any;
    export var DIRECTION_NONE:any;
    export default {};
}

declare module "eases" {
    export default {};
}

// https://github.com/feross/blob-to-buffer
declare module "blob-to-buffer" {
    function blobToBuffer(blob:Blob, cb:(err:Error, buffer:Buffer) => void): void;
    export = blobToBuffer;
}

declare module "expand-home-dir" {
    function expandHomeDir(path:string):string;
    export = expandHomeDir;
}
